const raw = $json.output || $json.text || $json.response || $json.message || JSON.stringify($json);

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let data;
try {
  data = JSON.parse(cleaned);
} catch (error) {
  throw new Error("AI output is not valid JSON: " + error.message + "\nRaw output:\n" + cleaned);
}

return [{ json: data }];

return [{
  json: {
    response_type: "success",
    message: "Claim status form checked and saved to Google Sheet.",
    claim_reference_number: $json.claim_tracking_row.claim_reference_number,
    form_status: $json.form_checker_result.form_status,
    data_quality_score: $json.form_checker_result.data_quality_score,
    checker_message: $json.form_checker_result.checker_message,
    next_action: $json.next_action,
    audit_note: $json.audit_note
  }
}];

return [{
  json: {
    response_type: "needs_review",
    message: "Claim status form was checked but not saved because it needs review.",
    claim_reference_number: $json.claim_tracking_row?.claim_reference_number || "",
    form_status: $json.form_checker_result.form_status,
    data_quality_score: $json.form_checker_result.data_quality_score,
    missing_fields: $json.form_checker_result.missing_fields,
    inconsistencies: $json.form_checker_result.inconsistencies,
    checker_message: $json.form_checker_result.checker_message,
    next_action: $json.next_action,
    audit_note: $json.audit_note
  }
}];
